import { use, useEffect, useState } from "react";

async function getData() {
    const resp = await fetch('https://dummyjson.com/products')
    const data = await resp.json()
    return data
}
function useData() {
    const [tableData, setTableData] = useState({
        loading: false,
        error: null,
        tableData: null
    })

   async function fetchData() {
    setData((prev) => {
        return {
          ...prev,
          loading: true
        }
    })
    try{
        const data = await getData()
        console.log('>>>>', data)
        setData((prev) => {
        return {
          ...prev,
          tableData: data
        }
        })
    } catch (err) {
setData((prev) => {
        return {
          ...prev,
          error: 'Error'
        }
        })
    } finally {
        setData((prev) => {
        return {
          ...prev,
          loading: false
        }
        })
    }
   }
    useEffect(() => {
      fetchData()
    },[])
}

export default useData
